onClick:
{{
(() => {

    // ==========================
    // VALIDAR CLAVE
    // ==========================

    if (
        qryAAFValidarClaveReversion.data?.[0]?.clave_valida !== 1
    ) {

        showAlert(
            "La clave de anulación es incorrecta.",
            "warning"
        );

        return;

    }

    // ==========================
    // VALIDAR MOTIVO
    // ==========================

    if (!inpMotivoReversionAAF.text?.trim()) {

        showAlert(
            "Debe indicar el motivo de la reversión.",
            "warning"
        );

        return;

    }

    // ==========================
    // REVERSAR
    // ==========================

    qryAAFReversar.run()

    .then(() => {

        closeModal("mdlReversionAAF");

        return Promise.all([

            inpClaveReversionAAF.setValue(""),

            inpMotivoReversionAAF.setValue(""),

            qryAAFConsultar.run()

        ]);

    })

    .then(() => {

        showAlert(
            "Aplicación reversada correctamente.",
            "success"
        );

    })

    .catch((e) => {

        showAlert(
            e.message,
            "error"
        );

    });

})();
}}
